505→private fun Note.ordToCardIndex(ord: Int): Int {
506→    return when {
507→        this.notetype.isCloze -> {
508→            // For cloze notes, find the index of the ordinal + 1 in the cloze numbers
509→            val clozeNumbers = col.clozeNumbersInNote(this)
510→            val index = clozeNumbers.indexOf(ord + 1)
511→            Timber.d("ordToCardIndex() cloze: ord=%d, clozeNumbers=%s, index=%d", ord, clozeNumbers, index)
512→            index
513→        }
514→        else -> ord
515→    }
516→}
